111				Code:    adapterkit.CodeInvalidParams,
112				Message: fmt.Sprintf("codex: skill %q asset %q is not in canonical form (cleaned: %q)", skillID, relPath, cleaned),
113			}
114		}
115		if cleaned == "." {
116			return &adapterkit.Error{
117				Code:    adapterkit.CodeInvalidParams,
118				Message: fmt.Sprintf("codex: skill %q asset rel_path must name a file, not the skill directory itself (got %q)", skillID, relPath),
