// produced from it. See docs/spec/ir-v1.md for the contract.
//
// The decoder is deterministic: same commit SHA → byte-identical IR
// (modulo Go map iteration in user-visible fields, which we explicitly
// sort).
func Decode(repo *git.Repository, commitSHA string, opts DecodeOptions) ([]Node, []Warning, error) {
	entries, err := repo.ReadTree(commitSHA)
	if err != nil {
		return nil, nil, fmt.Errorf("ir: read tree: %w", err)
	}

	var (
		nodes    []Node
		warnings []Warning
		// Track which skill directories we've seen and whether each has a
		// SKILL.md, so we can emit ErrSkillMissingSKILL for orphan dirs.
		skillDirs   = map[string]bool{} // dir -> hasSKILL
		hasAgentsMD = false
		seenIDs     = map[Kind]map[string]string{} // kind -> id -> first path
	)

	markSeen := func(k Kind, id, path string) error {
		if _, ok := seenIDs[k]; !ok {
			seenIDs[k] = map[string]string{}
		}
		if prev, dup := seenIDs[k][id]; dup {
			return fmt.Errorf("%w: kind=%s id=%s (first at %q, again at %q)",
				ErrDuplicateID, k, id, prev, path)
		}
		seenIDs[k][id] = path
		return nil
	}

	for _, e := range entries {
		// Skip directory entries — TreeEntry covers regular files; sub-
		// directories surface as their own entries with file-shaped paths.
		if isDir(e.Mode) {
			continue
		}

		p := e.Path
		switch {
		case p == "AGENTS.md":
			node, err := buildAgentsMD(repo, commitSHA, e, "" /* no overlay scope */)
			if err != nil {
				return nil, nil, err
			}
			if err := markSeen(KindAgentsMD, node.ID, p); err != nil {
				return nil, nil, err
			}
			nodes = append(nodes, node)
			hasAgentsMD = true

		case isOverlayPath(p):
			node, err := buildAgentsMD(repo, commitSHA, e, rootAgentsMDOverlay[p])
			if err != nil {
				return nil, nil, err
			}
			if err := markSeen(KindAgentsMD, node.ID, p); err != nil {
				return nil, nil, err
			}
			nodes = append(nodes, node)
			// An overlay (CLAUDE.md / GEMINI.md) counts as an
			// agents-md file for the purposes of WarnAgentsMDMissing:
			// the warning fires only when neither canonical nor any
			// overlay exists.
			hasAgentsMD = true

		case strings.HasPrefix(p, "rules/"):
			node, err := buildSimpleNode(repo, commitSHA, e, KindRule, "rules/", ".md")

package manifest

// Manifest is the v1 schema for `.agent-sync.yaml`.
//
// NOTE: This is a strict schema. Unknown keys are rejected at load time,
// except for forward-compat extension keys that start with `x-`.
type Manifest struct {
	Version int `yaml:"version"`

	Canonical CanonicalSource `yaml:"canonical"`

	// Targets is an optional list of tool targets to compile to. Empty means
	// "no targets" (a valid state for a workspace that is not yet configured).
	Targets []string `yaml:"targets,omitempty"`

	// Scope declares where the rendered config is intended to apply for the
	// target tools. v1 accepts: user, project, global.
	Scope string `yaml:"scope,omitempty"`

	Cache CacheConfig `yaml:"cache,omitempty"`

	Adapters []AdapterDecl `yaml:"adapters,omitempty"`

	// TrustedSHA is the project-level trust anchor. It mirrors `canonical.commit`
	// and is committed to git so CI can fail closed on drift. See plan decision #9.
	TrustedSHA string `yaml:"trusted_sha,omitempty"`

	Trust TrustConfig `yaml:"trust,omitempty"`
}

type CanonicalSource struct {
	// Exactly one of URL or LocalPath must be set.
	URL       string `yaml:"url,omitempty"`
	LocalPath string `yaml:"local_path,omitempty"`

	// Ref is an optional git ref name (branch, tag) used at init time before
	// resolving to Commit.
	Ref string `yaml:"ref,omitempty"`

	// Commit is the pinned git commit SHA (40 hex). Pinning is the default.
	Commit string `yaml:"commit,omitempty"`
}

type CacheConfig struct {
	// Override, if set, overrides the default cache root. This may be used for
	// workspace-local cache storage.
	Override string `yaml:"override,omitempty"`
}

type AdapterDecl struct {
	Name string `yaml:"name"`

	// Source may point to an out-of-tree adapter implementation. Bundled
	// adapters use an implicit source.
	Source string `yaml:"source,omitempty"`

	// Command, when set, overrides the argv slice the runtime would
	// otherwise infer from PATH. The first element is resolved against
	// $PATH unless it contains a path separator.
	Command []string `yaml:"command,omitempty"`

	// Version is a free-form version pin for the adapter. Compared by
	// humans; the runtime does not interpret it.
	Version string `yaml:"version,omitempty"`

	// ReservedPrefix is the path prefix (relative to the workspace root)
	// the adapter owns. Trailing slashes are stripped on load. The
	// runtime rejects configurations where one adapter's prefix is
	// nested inside another's.
	ReservedPrefix string `yaml:"reserved_prefix,omitempty"`
}

type TrustConfig struct {
}

