1	package manifest
2	
3	import (
4		"errors"
5		"fmt"
6		"os"
7		"path"
8		"path/filepath"
9		"regexp"
10		"strings"
11	
12		"github.com/goccy/go-yaml"
13	)
14	
15	type LoadOptions struct {
16		// NonInteractive enforces the CI-safe invariant: if `canonical.commit` is
17		// set, `trusted_sha` must also be set.
18		NonInteractive bool
19	}
20	
21	var (
22		ErrInvalidManifest = errors.New("invalid manifest")
23	
24		// ErrInvalidReservedPrefix is returned by ValidateReservedPrefix when
25		// a reserved_prefix value is not a clean, workspace-relative,
26		// forward-slash path. Wrapped by ErrInvalidManifest at call sites in
27		// the workspace-manifest validator so existing callers can continue
28		// to branch on errors.Is(err, ErrInvalidManifest).
29		ErrInvalidReservedPrefix = errors.New("manifest: reserved_prefix must be a clean workspace-relative forward-slash path")
30	
31		reHex40 = regexp.MustCompile(`\A[0-9a-f]{40}\z`)
32	
33		// reWindowsVolumePrefix matches a leading drive letter ("C:", "d:", ...)
34		// — absolute on Windows when interpreted by OS path rules. We reject
35		// it on every OS so workspace-relative paths stay portable.
36		reWindowsVolumePrefix = regexp.MustCompile(`\A[A-Za-z]:`)
37	)
38	
39	// ValidateReservedPrefix is the single canonical validator for
40	// adapter-style reserved_prefix values. The contract: an empty string
41	// (no claim) is allowed and returns ""; otherwise the value must be a
42	// clean, workspace-relative, forward-slash path. The returned string is
43	// the normalized form (path.Clean with any trailing "/" already
44	// stripped).
45	//
46	// Rejected shapes (all wrap ErrInvalidReservedPrefix):
47	//   - any backslash (always reserved on POSIX, ambiguous on Windows)
48	//   - Windows volume prefix ("C:foo", "d:/x")
49	//   - absolute paths under POSIX rules (leading "/")
50	//   - any path segment equal to ".." (workspace escape)
51	func ValidateReservedPrefix(s string) (string, error) {
52		if s == "" {
53			return "", nil
54		}
55		// Always-applicable Windows-safety checks: backslashes and volume
56		// prefixes never belong in a forward-slash workspace path, and on
57		// POSIX path.IsAbs misses both shapes — so we reject them on every
58		// OS rather than relying on the caller's runtime.GOOS.
59		if strings.ContainsRune(s, '\\') {
60			return "", fmt.Errorf("%w: contains backslash: %q", ErrInvalidReservedPrefix, s)
61		}
62		if reWindowsVolumePrefix.MatchString(s) {
63			return "", fmt.Errorf("%w: contains Windows volume prefix: %q", ErrInvalidReservedPrefix, s)
64		}
65		if path.IsAbs(s) {
66			return "", fmt.Errorf("%w: must be relative, got absolute: %q", ErrInvalidReservedPrefix, s)
67		}
68		// Reject ".." segments before Clean collapses them. path.Clean
69		// would silently turn "foo/../bar" into "bar", losing the
70		// traversal intent — rejecting on the original segments preserves
71		// the operator's signal that they wrote something that escapes the
72		// declared subtree.
73		for _, seg := range strings.Split(s, "/") {
74			if seg == ".." {
75				return "", fmt.Errorf("%w: contains parent-directory segment: %q", ErrInvalidReservedPrefix, s)
76			}
77		}
78		// Trim trailing "/" before Clean so a value like ".claude/" round-trips
79		// to ".claude" (preserving the existing public contract) rather than
80		// being treated as a directory by path.Clean.
81		trimmed := strings.TrimRight(s, "/")
82		cleaned := path.Clean(trimmed)
83		return cleaned, nil
84	}
85	
86	// MaxManifestSize is the maximum allowed manifest file size (1 MiB).
87	const MaxManifestSize = 1 << 20
88	
89	func LoadFile(path string, opts LoadOptions) (*Manifest, error) {
90		info, err := os.Stat(path)
91		if err != nil {
92			return nil, fmt.Errorf("manifest: stat %q: %w", path, err)
93		}
94		if info.Size() > MaxManifestSize {
95			return nil, fmt.Errorf("%w: manifest exceeds %d bytes (got %d)", ErrInvalidManifest, MaxManifestSize, info.Size())
96		}
97		b, err := os.ReadFile(path)
98		if err != nil {
99			return nil, fmt.Errorf("manifest: read %q: %w", path, err)
100		}
101		// Defense-in-depth: file could grow between stat and read.
102		if len(b) > MaxManifestSize {
103			return nil, fmt.Errorf("%w: manifest exceeds %d bytes (got %d)", ErrInvalidManifest, MaxManifestSize, len(b))
104		}
105		return LoadBytes(b, opts)
106	}
107	
108	func LoadBytes(src []byte, opts LoadOptions) (*Manifest, error) {
109		var m Manifest
110		if err := yaml.UnmarshalWithOptions(
111			src,
112			&m,
113			yaml.DisallowUnknownField(),
114			yaml.AllowFieldPrefixes("x-"),
115		); err != nil {
116			return nil, fmt.Errorf("%w: %s", ErrInvalidManifest, yaml.FormatError(err, false, true))
117		}
118	
119		if err := Validate(&m, opts); err != nil {
120			return nil, err
121		}
122		return &m, nil
123	}
124	
125	func Validate(m *Manifest, opts LoadOptions) error {
126		if m == nil {
127			return fmt.Errorf("%w: manifest is nil", ErrInvalidManifest)
128		}
129	
130		if m.Version == 0 {
131			// Default to v1 for the greenfield phase. Once agent-sync ships, this
132			// should become required.
133			m.Version = 1
134		}
135		if m.Version != 1 {
136			return fmt.Errorf("%w: unsupported manifest version %d (want 1)", ErrInvalidManifest, m.Version)
137		}
138	
139		// Normalize scalar fields before any checks.
140		m.Canonical.URL = strings.TrimSpace(m.Canonical.URL)
141		m.Canonical.LocalPath = strings.TrimSpace(m.Canonical.LocalPath)
142	
143		// Canonical source 1:1 invariant: exactly one of url/local_path.
144		hasURL := m.Canonical.URL != ""
145		hasLocal := m.Canonical.LocalPath != ""
146		switch {
147		case hasURL && hasLocal:
148			return fmt.Errorf("%w: canonical source must set exactly one of url or local_path (got both)", ErrInvalidManifest)
149		case !hasURL && !hasLocal:
150			return fmt.Errorf("%w: canonical source must set exactly one of url or local_path (got neither)", ErrInvalidManifest)
151		}
152	
153		commit := strings.TrimSpace(m.Canonical.Commit)
154		trusted := strings.TrimSpace(m.TrustedSHA)
155	
156		if trusted != "" && commit == "" {
157			return fmt.Errorf("%w: trusted_sha is set but canonical.commit is empty (no floating-with-pin hybrid)", ErrInvalidManifest)
158		}
159		if commit != "" && !reHex40.MatchString(commit) {
160			return fmt.Errorf("%w: canonical.commit must be 40 lowercase hex (got %q)", ErrInvalidManifest, commit)
161		}
162		m.Canonical.Commit = commit
163	
164		if trusted != "" && !reHex40.MatchString(trusted) {
165			return fmt.Errorf("%w: trusted_sha must be 40 lowercase hex (got %q)", ErrInvalidManifest, trusted)
166		}
167		m.TrustedSHA = trusted
168	
169		if opts.NonInteractive && commit != "" && trusted == "" {
170			return fmt.Errorf("%w: non-interactive mode requires trusted_sha when canonical.commit is set", ErrInvalidManifest)
171		}
172		if commit != "" && trusted != "" && commit != trusted {
173			return fmt.Errorf("%w: trusted_sha must mirror canonical.commit (commit=%q trusted_sha=%q)", ErrInvalidManifest, commit, trusted)
174		}
175	
176		switch m.Scope {
177		case "", "user", "project", "global":
178		default:
179			return fmt.Errorf("%w: scope must be one of user|project|global (got %q)", ErrInvalidManifest, m.Scope)
180		}
181	
182		if m.Cache.Override != "" {
183			override := strings.TrimSpace(m.Cache.Override)
184			m.Cache.Override = override
185			if !filepath.IsAbs(override) {
186				return fmt.Errorf("%w: cache.override must be absolute, got %q", ErrInvalidManifest, override)
187			}
188			// Check the original (pre-Clean) path segments for ".." to reject
189			// explicit traversal intent (e.g. "/home/alice/../../etc") even when
190			// filepath.Clean would collapse it to a valid-looking path.
191			// strings.Contains(override, "..") is intentionally NOT used: it would
192			// also reject legitimate names like "/var/..cache".
193			for _, seg := range strings.Split(override, string(filepath.Separator)) {
194				if seg == ".." {
195					return fmt.Errorf("%w: cache.override must not contain .. segments, got %q", ErrInvalidManifest, override)
196				}
197			}
198			m.Cache.Override = filepath.Clean(override)
199		}
200	
201		if err := validateAdapters(m); err != nil {
202			return err
203		}
204	
205		return nil
206	}
207	
208	// reAdapterName mirrors the IR-id grammar. Adapter names must satisfy
209	// it because they appear in PATH lookups (agent-sync-adapter-<name>) and
210	// must be safe across filesystems.
211	var reAdapterName = regexp.MustCompile(`\A[a-z0-9][a-z0-9_-]{0,63}\z`)
212	
213	func validateAdapters(m *Manifest) error {
214		seen := make(map[string]bool, len(m.Adapters))
215		for i := range m.Adapters {
216			a := &m.Adapters[i]
217			if !reAdapterName.MatchString(a.Name) {
218				return fmt.Errorf("%w: adapters[%d].name=%q does not match required pattern", ErrInvalidManifest, i, a.Name)
219			}
220			if seen[a.Name] {
221				return fmt.Errorf("%w: adapters has duplicate name %q", ErrInvalidManifest, a.Name)
222			}
223			seen[a.Name] = true
224			for j, arg := range a.Command {
225				if strings.TrimSpace(arg) == "" {
226					return fmt.Errorf("%w: adapters[%d].command[%d] is empty", ErrInvalidManifest, i, j)
227				}
228			}
229			cleaned, err := ValidateReservedPrefix(a.ReservedPrefix)
230			if err != nil {
231				// Keep ErrInvalidManifest in the chain so existing callers
232				// branching on errors.Is(err, ErrInvalidManifest) still match;
233				// callers wanting the specific cause can branch on
234				// ErrInvalidReservedPrefix as well.
235				return fmt.Errorf("%w: adapters[%d].reserved_prefix: %w", ErrInvalidManifest, i, err)
236			}
237			a.ReservedPrefix = cleaned
238		}
239		return nil
240	}
