	ws := t.TempDir()
	if err := os.MkdirAll(filepath.Join(ws, ".agents"), 0o755); err != nil {
		t.Fatalf("mkdir: %v", err)
	}
	r := openReader(t, ws, ".agents")
	entries, err := r.ReadTree("")
	if err != nil {
